// ProductService.java (business logic for product search)
@Service
public class ProductServiceImpl implements ProductService {
    
    @Autowired
    private ElasticsearchTemplate elasticsearchTemplate;
    
    public void indexProduct(Product product) {
        Map<String, Object> map = new HashMap<>();
        map.put("id", product.getId());
        map.put("name", product.getName());
        map.put("description", product.getDescription());
        map.put("keywords", product.getKeywords());
        
        elasticsearchTemplate.index("products", product.getId(), map);
    }
    
    public List<Product> searchProducts(String query) {
        SearchQuery searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.matchQuery("keywords", query))
                .build();
        
        return elasticsearchTemplate.queryForList(searchQuery, Product.class);
    }
}

